@HttpExchange(url = "/movie")
public interface MovieListsRequests {

}

package dev.prince.movieez.media.tmdb.requests;

import dev.prince.movieez.media.models.movies.MovieNowPlayingModel;
import dev.prince.movieez.media.models.movies.MoviePopularModel;
import dev.prince.movieez.media.models.movies.MovieTopRatedModel;
import dev.prince.movieez.media.models.movies.MovieUpcomingModel;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.service.annotation.GetExchange;
import org.springframework.web.service.annotation.HttpExchange;

@HttpExchange(url = "/movie")
public interface MovieListsRequests {

  @GetExchange("/now_playing")
  MovieNowPlayingModel getNowPlaying(
      @RequestParam(value = "language")
      String language,
      @RequestParam(value = "page")
      int page,
      @RequestParam(value = "region", required = false)
      String region
  );

  @GetExchange("/popular")
  MoviePopularModel getPopular(
      @RequestParam(value = "language")
      String language,
      @RequestParam(value = "page")
      int page,
      @RequestParam(value = "region", required = false)
      String region
  );

  @GetExchange("/top_rated")
  MovieTopRatedModel getTopRated(
      @RequestParam(value = "language")
      String language,
      @RequestParam(value = "page")
      int page,
      @RequestParam(value = "region", required = false)
      String region
  );

  @GetExchange("/upcoming")
  MovieUpcomingModel getUpcoming(
      @RequestParam(value = "language")
      String language,
      @RequestParam(value = "page")
      int page,
      @RequestParam(value = "region", required = false)
      String region
  );
}

import { Component, inject, OnInit, signal, Signal, WritableSignal } from '@angular/core';
import { UserLocalPlaylistService } from '@shared/services/user/user-local-playlist.service';
import { OfflinePlaylist } from '@shared/models';
import { HlmItemImports } from '@spartan-ng/helm/item';
import { HlmButtonImports } from '@spartan-ng/helm/button';
import { provideIcons } from '@ng-icons/core';
import { lucideCheck, lucideMinus, lucideMoreVertical, lucidePlus } from '@ng-icons/lucide';
import { NgScrollbar } from 'ngx-scrollbar';
import { HlmScrollAreaImports } from '@spartan-ng/helm/scroll-area';
import { BrnDialogRef, injectBrnDialogContext } from '@spartan-ng/brain/dialog';
import { ShowPlaylistsDirectiveContext } from '@shared/directives/show-playlists-directive';
import { toast, ToastT } from '@spartan-ng/brain/sonner';
import { HlmSeparatorImports } from '@spartan-ng/helm/separator';
import { HlmDialogImports } from '@spartan-ng/helm/dialog';
import { HlmDropdownMenuImports } from '@spartan-ng/helm/dropdown-menu';
import { HlmIconImports } from '@spartan-ng/helm/icon';
import { HlmInputGroupImports } from '@spartan-ng/helm/input-group';
import { AutofocusDirective } from '@shared/directives/autofocus-directive';
import { HlmAlertDialogImports } from '@spartan-ng/helm/alert-dialog';

@Component({
  selector: 'me-playlist-dialog',
  imports: [
    HlmItemImports,
    HlmButtonImports,
    NgScrollbar,
    HlmScrollAreaImports,
    HlmSeparatorImports,
    HlmDialogImports,
    HlmDropdownMenuImports,
    HlmIconImports,
    HlmInputGroupImports,
    AutofocusDirective,
    HlmAlertDialogImports,
  ],
  templateUrl: './playlist-dialog.me.html',
  styleUrl: './playlist-dialog.me.css',
  providers: [provideIcons({ lucidePlus, lucideMinus, lucideMoreVertical, lucideCheck })],
})
export class PlaylistDialogMe implements OnInit {
  private static readonly DEFAULT_PLAYLIST_NAME = 'Favorites';
  private static readonly SHARED_TOAST_OPTIONS: Omit<ToastT, 'id' | 'type' | 'title'> = {
    position: 'top-right',
  };
  private readonly localPlaylistService: UserLocalPlaylistService =
    inject(UserLocalPlaylistService);
  private readonly dialogRef: BrnDialogRef<PlaylistDialogMe> =
    inject<BrnDialogRef<PlaylistDialogMe>>(BrnDialogRef);
  private readonly dialogContext = injectBrnDialogContext<ShowPlaylistsDirectiveContext>();

  protected readonly localPlaylists: Signal<OfflinePlaylist[]> =
    this.localPlaylistService.playlists;
  protected readonly currentEditingPlaylist: WritableSignal<string | undefined> = signal(undefined);

  public ngOnInit(): void {
    this.localPlaylistService.createPlaylist(PlaylistDialogMe.DEFAULT_PLAYLIST_NAME);
    console.debug(`Current dialog context:`, this.dialogContext.trackId);
  }

  protected handlePlaylistButtonClick(name: string): void {
    if (this.isTrackInPlaylist(name)) {
      this.removeFromPlaylist(name);
    } else {
      this.addToPlaylist(name);
    }
  }

  protected addToPlaylist(name: string): void {
    const trackId: string = this.dialogContext.trackId;
    if (trackId.trim() === '') {
      this.closeDialog();
      return;
    }

    if (this.isTrackInPlaylist(name)) {
      this.handleTrackAlreadyInPlaylist(name);
      return;
    }

    this.handleAddingToPlaylist(name);
  }

  protected removeFromPlaylist(name: string): void {
    const trackId: string = this.dialogContext.trackId;

    if (trackId.trim() === '') {
      this.closeDialog();
      return;
    }

    if (!this.isTrackInPlaylist(name)) {
      this.handleTrackIsNotInPlaylist(name);
      return;
    }

    this.handleRemovingFromPlaylist(name);
  }

  protected isTrackInPlaylist(name: string): boolean {
    const playlist: OfflinePlaylist | undefined = this.localPlaylists().find(
      (pl) => pl.name === name,
    );
    if (!playlist) {
      return false;
    }
    const trackId: string = this.dialogContext.trackId;
    return playlist.items?.some((item) => item.trackId === trackId) ?? false;
  }

  protected closeDialog(): void {
    this.dialogRef.close();
  }

  protected handleEditPlaylist(name: string): void {
    this.currentEditingPlaylist.set(name);
  }

  protected handleDeletePlaylist(name: string): void {
    this.localPlaylistService.deletePlaylist(name);
  }

  protected handleSavePlaylistName(event: Event, name: string): void {
    event.stopPropagation();
    const newName: string = name.trim();

    if (newName.length === 0) {
      console.debug(
        `Attempted to rename playlist to an empty name. Current editing playlist: "${this.currentEditingPlaylist()}".`,
      );
      toast.error(`Playlist name cannot be empty.`, PlaylistDialogMe.SHARED_TOAST_OPTIONS);
      this.currentEditingPlaylist.set(undefined);
      return;
    }

    if (
      this.localPlaylistService.getPlaylist(newName) &&
      newName !== this.currentEditingPlaylist()
    ) {
      console.debug(
        `Playlist with name "${newName}" already exists. Current editing playlist: "${this.currentEditingPlaylist()}".`,
      );
      toast.error(
        `A playlist with the name "${newName}" already exists. Please choose a different name.`,
        PlaylistDialogMe.SHARED_TOAST_OPTIONS,
      );
      this.currentEditingPlaylist.set(undefined);
      return;
    }

    this.localPlaylistService.renamePlaylist(this.currentEditingPlaylist()!, newName);
    this.currentEditingPlaylist.set(undefined);
  }

  protected createNewPlaylist() {
    const baseName = 'New Playlist';
    let newName = baseName;
    let counter = 1;

    while (this.localPlaylistService.getPlaylist(newName)) {
      newName = `${baseName} (${counter})`;
      counter++;
    }

    this.localPlaylistService.createPlaylist(newName);
  }

  protected handleDeleteAllPlaylists(context: any) {
    context.close();
    this.localPlaylistService.deleteAllPlaylists();
  }

  private handleTrackAlreadyInPlaylist(name: string): void {
    toast.error(
      `Track is already in the playlist "${name}".`,
      PlaylistDialogMe.SHARED_TOAST_OPTIONS,
    );
    this.closeDialog();
  }

  private handleAddingToPlaylist(name: string): void {
    this.localPlaylistService.addToPlaylist(name, this.dialogContext.trackId);
    toast.success(`Track added to playlist "${name}".`, PlaylistDialogMe.SHARED_TOAST_OPTIONS);
  }

  private handleRemovingFromPlaylist(name: string): void {
    this.localPlaylistService.removeFromPlaylist(name, this.dialogContext.trackId);
    toast.success(`Track removed from playlist "${name}".`, PlaylistDialogMe.SHARED_TOAST_OPTIONS);
  }

  private handleTrackIsNotInPlaylist(name: string): void {
    toast.error(`Track is not in the playlist "${name}".`, PlaylistDialogMe.SHARED_TOAST_OPTIONS);
    this.closeDialog();
  }
}

import { Component, inject, OnInit, signal, Signal, WritableSignal } from '@angular/core';
import { UserLocalPlaylistService } from '@shared/services/user/user-local-playlist.service';
import { OfflinePlaylist } from '@shared/models';
import { HlmItemImports } from '@spartan-ng/helm/item';
import { HlmButtonImports } from '@spartan-ng/helm/button';
import { provideIcons } from '@ng-icons/core';
import { lucideCheck, lucideMinus, lucideMoreVertical, lucidePlus } from '@ng-icons/lucide';
import { NgScrollbar } from 'ngx-scrollbar';
import { HlmScrollAreaImports } from '@spartan-ng/helm/scroll-area';
import { BrnDialogRef, injectBrnDialogContext } from '@spartan-ng/brain/dialog';
import { ShowPlaylistsDirectiveContext } from '@shared/directives/show-playlists-directive';
import { toast, ToastT } from '@spartan-ng/brain/sonner';
import { HlmSeparatorImports } from '@spartan-ng/helm/separator';
import { HlmDialogImports } from '@spartan-ng/helm/dialog';
import { HlmDropdownMenuImports } from '@spartan-ng/helm/dropdown-menu';
import { HlmIconImports } from '@spartan-ng/helm/icon';
import { HlmInputGroupImports } from '@spartan-ng/helm/input-group';
import { AutofocusDirective } from '@shared/directives/autofocus-directive';
import { HlmAlertDialogImports } from '@spartan-ng/helm/alert-dialog';

@Component({
  selector: 'me-playlist-dialog',
  imports: [
    HlmItemImports,
    HlmButtonImports,
    NgScrollbar,
    HlmScrollAreaImports,
    HlmSeparatorImports,
    HlmDialogImports,
    HlmDropdownMenuImports,
    HlmIconImports,
    HlmInputGroupImports,
    AutofocusDirective,
    HlmAlertDialogImports,
  ],
  templateUrl: './playlist-dialog.me.html',
  styleUrl: './playlist-dialog.me.css',
  providers: [provideIcons({ lucidePlus, lucideMinus, lucideMoreVertical, lucideCheck })],
})
export class PlaylistDialogMe implements OnInit {
  private static readonly DEFAULT_PLAYLIST_NAME = 'Favorites';
  private static readonly SHARED_TOAST_OPTIONS: Omit<ToastT, 'id' | 'type' | 'title'> = {
    position: 'top-right',
  };
  private readonly localPlaylistService: UserLocalPlaylistService =
    inject(UserLocalPlaylistService);
  private readonly dialogRef: BrnDialogRef<PlaylistDialogMe> =
    inject<BrnDialogRef<PlaylistDialogMe>>(BrnDialogRef);
  private readonly dialogContext = injectBrnDialogContext<ShowPlaylistsDirectiveContext>();

  protected readonly localPlaylists: Signal<OfflinePlaylist[]> =
    this.localPlaylistService.playlists;
  protected readonly currentEditingPlaylist: WritableSignal<string | undefined> = signal(undefined);

  public ngOnInit(): void {
    this.localPlaylistService
      .createPlaylist(PlaylistDialogMe.DEFAULT_PLAYLIST_NAME)
      .subscribe();
    console.debug(`Current dialog context:`, this.dialogContext.trackId);
  }

  protected handlePlaylistButtonClick(name: string): void {
    if (this.isTrackInPlaylist(name)) {
      this.removeFromPlaylist(name);
    } else {
      this.addToPlaylist(name);
    }
  }

  protected addToPlaylist(name: string): void {
    const trackId: string = this.dialogContext.trackId;
    if (trackId.trim() === '') {
      this.closeDialog();
      return;
    }

    if (this.isTrackInPlaylist(name)) {
      this.handleTrackAlreadyInPlaylist(name);
      return;
    }

    this.handleAddingToPlaylist(name);
  }

  protected removeFromPlaylist(name: string): void {
    const trackId: string = this.dialogContext.trackId;

    if (trackId.trim() === '') {
      this.closeDialog();
      return;
    }

    if (!this.isTrackInPlaylist(name)) {
      this.handleTrackIsNotInPlaylist(name);
      return;
    }

    this.handleRemovingFromPlaylist(name);
  }

  protected isTrackInPlaylist(name: string): boolean {
    const playlist: OfflinePlaylist | undefined = this.localPlaylists().find(
      (pl) => pl.name === name,
    );
    if (!playlist) {
      return false;
    }
    const trackId: string = this.dialogContext.trackId;
    return playlist.items?.some((item) => item.trackId === trackId) ?? false;
  }

  protected closeDialog(): void {
    this.dialogRef.close();
  }

  protected handleEditPlaylist(name: string): void {
    this.currentEditingPlaylist.set(name);
  }

  protected handleDeletePlaylist(name: string): void {
    this.localPlaylistService.deletePlaylist(name);
  }

  protected handleSavePlaylistName(event: Event, name: string): void {
    event.stopPropagation();
    const newName: string = name.trim();

    if (newName.length === 0) {
      console.debug(
        `Attempted to rename playlist to an empty name. Current editing playlist: "${this.currentEditingPlaylist()}".`,
      );
      toast.error(`Playlist name cannot be empty.`, PlaylistDialogMe.SHARED_TOAST_OPTIONS);
      this.currentEditingPlaylist.set(undefined);
      return;
    }

    const isNameTaken: boolean =
      this.localPlaylists().some((playlist) => playlist.name === newName) &&
      newName !== this.currentEditingPlaylist();
    if (isNameTaken) {
      console.debug(
        `Playlist with name "${newName}" already exists. Current editing playlist: "${this.currentEditingPlaylist()}".`,
      );
      toast.error(
        `A playlist with the name "${newName}" already exists. Please choose a different name.`,
        PlaylistDialogMe.SHARED_TOAST_OPTIONS,
      );
      this.currentEditingPlaylist.set(undefined);
      return;
    }

    this.localPlaylistService
      .renamePlaylist(this.currentEditingPlaylist()!, newName)
      .subscribe();
    this.currentEditingPlaylist.set(undefined);
  }

  protected createNewPlaylist() {
    const baseName = 'New Playlist';
    let newName = baseName;
    let counter = 1;

    while (this.localPlaylists().some((playlist) => playlist.name === newName)) {
      newName = `${baseName} (${counter})`;
      counter++;
    }

    this.localPlaylistService.createPlaylist(newName).subscribe();
  }

  protected handleDeleteAllPlaylists(context: any) {
    context.close();
    this.localPlaylistService.deleteAllPlaylists();
  }

  private handleTrackAlreadyInPlaylist(name: string): void {
    toast.error(
      `Track is already in the playlist "${name}".`,
      PlaylistDialogMe.SHARED_TOAST_OPTIONS,
    );
    this.closeDialog();
  }

  private handleAddingToPlaylist(name: string): void {
    this.localPlaylistService.addToPlaylist(name, this.dialogContext.trackId).subscribe();
    toast.success(`Track added to playlist "${name}".`, PlaylistDialogMe.SHARED_TOAST_OPTIONS);
  }

  private handleRemovingFromPlaylist(name: string): void {
    this.localPlaylistService
      .removeFromPlaylist(name, this.dialogContext.trackId)
      .subscribe();
    toast.success(`Track removed from playlist "${name}".`, PlaylistDialogMe.SHARED_TOAST_OPTIONS);
  }

  private handleTrackIsNotInPlaylist(name: string): void {
    toast.error(`Track is not in the playlist "${name}".`, PlaylistDialogMe.SHARED_TOAST_OPTIONS);
    this.closeDialog();
  }
}

import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { environment } from '@environments/environment';
import {
  AddTracksToPlaylistInput,
  AddTrackToPlaylistInput,
  CreateUserPlaylistInput,
  DeletePlaylistInput,
  DeleteTrackFromPlaylistInput,
  GetUserPlaylistInput,
  PlaylistContentDto,
  PlaylistDto,
  ServerResponse,
} from '@shared/models';
import { PlaylistService } from '@shared/services/user/user-local-playlist.service';
import { AbstractMediaBackendService } from '@shared/services/media/abstract-media-backend-service';

@Injectable({
  providedIn: 'root',
})
export class UserPlaylistService extends AbstractMediaBackendService implements PlaylistService {
  constructor() {
    super(`${environment.api.baseUrl}users/playlists/`);
  }

  public createPlaylist(name: string): Observable<PlaylistDto> {
    throw new Error('Method not implemented.');
  }

  public deletePlaylist(name: string): Observable<void> {
    throw new Error('Method not implemented.');
  }

  public getPlaylist(playlistName: string): Observable<PlaylistDto | null> {
    throw new Error('Method not implemented.');
  }

  public removeFromPlaylist(playlistName: string, trackId: string): Observable<PlaylistDto | null> {
    throw new Error('Method not implemented.');
  }

  public addToPlaylist(playlistName: string, trackId: string): Observable<PlaylistDto | null> {
    throw new Error('Method not implemented.');
  }

  public renamePlaylist(oldName: string, newName: string): Observable<PlaylistDto | null> {
    throw new Error('Method not implemented.');
  }

  public getPlaylists(): Observable<ServerResponse<PlaylistDto[]>> {
    return this.performRequest<ServerResponse<PlaylistDto[]>, undefined>(
      `${this.baseUrl}all`,
      undefined,
    );
  }

  public getOnlinePlaylistByName(
    input: GetUserPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto | null>> {
    const encodedName = encodeURIComponent(input.name);
    return this.performRequest<ServerResponse<PlaylistDto | null>, undefined>(encodedName);
  }

  public getOnlinePlaylistContents(
    input: GetUserPlaylistInput,
  ): Observable<ServerResponse<PlaylistContentDto[]>> {
    const encodedName = encodeURIComponent(input.name);
    return this.performRequest<ServerResponse<PlaylistContentDto[]>, undefined>(
      `${this.baseUrl}${encodedName}/tracks`,
    );
  }

  public createOnlinePlaylist(
    input: CreateUserPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto>> {
    const encodedName = encodeURIComponent(input.name);
    return this.client.post<ServerResponse<PlaylistDto>>(`${this.baseUrl}${encodedName}`, null);
  }

  public updatePlaylistName(name: string, newName: string) {
    const encodedName = encodeURIComponent(name);
    const encodedNewName = encodeURIComponent(newName);
    return this.client.patch<ServerResponse<PlaylistDto>>(
      `${this.baseUrl}${encodedName}`,
      encodedNewName,
    );
  }

  public addTrackToOnlinePlaylist(
    input: AddTrackToPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto>> {
    const encodedName = encodeURIComponent(input.name);
    const encodedTrackId = encodeURIComponent(input.trackId);
    return this.client.post<ServerResponse<PlaylistDto>>(
      `${this.baseUrl}${encodedName}/tracks/${encodedTrackId}`,
      null,
    );
  }

  public addAllTracksToOnlinePlaylist(
    input: AddTracksToPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto>> {
    const encodedName = encodeURIComponent(input.name);
    return this.client.post<ServerResponse<PlaylistDto>>(
      `${this.baseUrl}${encodedName}/tracks`,
      input.trackIds,
    );
  }

  public deleteOnlinePlaylist(input: DeletePlaylistInput): Observable<ServerResponse<null>> {
    const encodedName = encodeURIComponent(input.name);
    return this.client.delete<ServerResponse<null>>(`${this.baseUrl}${encodedName}`);
  }

  public deleteTrackFromPlaylist(
    input: DeleteTrackFromPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto>> {
    const encodedName = encodeURIComponent(input.name);
    const encodedTrackId = encodeURIComponent(input.trackId);
    return this.client.delete<ServerResponse<PlaylistDto>>(
      `${this.baseUrl}${encodedName}/tracks/${encodedTrackId}`,
    );
  }
}

import { Injectable } from '@angular/core';
import { Observable, map } from 'rxjs';
import { environment } from '@environments/environment';
import {
  AddTracksToPlaylistInput,
  AddTrackToPlaylistInput,
  CreateUserPlaylistInput,
  DeletePlaylistInput,
  DeleteTrackFromPlaylistInput,
  GetUserPlaylistInput,
  PlaylistContentDto,
  PlaylistDto,
  ServerResponse,
} from '@shared/models';
import { PlaylistService } from '@shared/services/user/user-local-playlist.service';
import { AbstractMediaBackendService } from '@shared/services/media/abstract-media-backend-service';

@Injectable({
  providedIn: 'root',
})
export class UserPlaylistService extends AbstractMediaBackendService implements PlaylistService {
  constructor() {
    super(`${environment.api.baseUrl}users/playlists/`);
  }

  public createPlaylist(name: string): Observable<PlaylistDto> {
    return this.createOnlinePlaylist({ name }).pipe(map((response) => response.details));
  }

  public deletePlaylist(name: string): Observable<void> {
    return this.deleteOnlinePlaylist({ name }).pipe(map(() => undefined));
  }

  public getPlaylist(playlistName: string): Observable<PlaylistDto | null> {
    return this.getOnlinePlaylistByName({ name: playlistName }).pipe(
      map((response) => response.details ?? null),
    );
  }

  public removeFromPlaylist(playlistName: string, trackId: string): Observable<PlaylistDto | null> {
    return this.deleteTrackFromPlaylist({ name: playlistName, trackId }).pipe(
      map((response) => response.details ?? null),
    );
  }

  public addToPlaylist(playlistName: string, trackId: string): Observable<PlaylistDto | null> {
    return this.addTrackToOnlinePlaylist({ name: playlistName, trackId }).pipe(
      map((response) => response.details ?? null),
    );
  }

  public renamePlaylist(oldName: string, newName: string): Observable<PlaylistDto | null> {
    return this.updatePlaylistName(oldName, newName).pipe(
      map((response) => response.details ?? null),
    );
  }

  public getPlaylists(): Observable<ServerResponse<PlaylistDto[]>> {
    return this.performRequest<ServerResponse<PlaylistDto[]>, undefined>('all');
  }

  public getOnlinePlaylistByName(
    input: GetUserPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto | null>> {
    const encodedName = encodeURIComponent(input.name);
    return this.performRequest<ServerResponse<PlaylistDto | null>, undefined>(encodedName);
  }

  public getOnlinePlaylistContents(
    input: GetUserPlaylistInput,
  ): Observable<ServerResponse<PlaylistContentDto[]>> {
    const encodedName = encodeURIComponent(input.name);
    return this.performRequest<ServerResponse<PlaylistContentDto[]>, undefined>(
      `${encodedName}/tracks`,
    );
  }

  public createOnlinePlaylist(
    input: CreateUserPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto>> {
    const encodedName = encodeURIComponent(input.name);
    return this.client.post<ServerResponse<PlaylistDto>>(`${this.baseUrl}${encodedName}`, null);
  }

  public updatePlaylistName(name: string, newName: string) {
    const encodedName = encodeURIComponent(name);
    const encodedNewName = encodeURIComponent(newName);
    return this.client.patch<ServerResponse<PlaylistDto>>(
      `${this.baseUrl}${encodedName}`,
      encodedNewName,
    );
  }

  public addTrackToOnlinePlaylist(
    input: AddTrackToPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto>> {
    const encodedName = encodeURIComponent(input.name);
    const encodedTrackId = encodeURIComponent(input.trackId);
    return this.client.post<ServerResponse<PlaylistDto>>(
      `${this.baseUrl}${encodedName}/tracks/${encodedTrackId}`,
      null,
    );
  }

  public addAllTracksToOnlinePlaylist(
    input: AddTracksToPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto>> {
    const encodedName = encodeURIComponent(input.name);
    return this.client.post<ServerResponse<PlaylistDto>>(
      `${this.baseUrl}${encodedName}/tracks`,
      input.trackIds,
    );
  }

  public deleteOnlinePlaylist(input: DeletePlaylistInput): Observable<ServerResponse<null>> {
    const encodedName = encodeURIComponent(input.name);
    return this.client.delete<ServerResponse<null>>(`${this.baseUrl}${encodedName}`);
  }

  public deleteTrackFromPlaylist(
    input: DeleteTrackFromPlaylistInput,
  ): Observable<ServerResponse<PlaylistDto>> {
    const encodedName = encodeURIComponent(input.name);
    const encodedTrackId = encodeURIComponent(input.trackId);
    return this.client.delete<ServerResponse<PlaylistDto>>(
      `${this.baseUrl}${encodedName}/tracks/${encodedTrackId}`,
    );
  }
}
